from html.parser import HTMLParser


class _LinkExtractor(HTMLParser):
    def __init__(self):
        super().__init__()
        self.links = []

    def handle_starttag(self, tag, attrs):
        if tag == "a":
            for name, value in attrs:
                if name == "href":
                    self.links.append(value)


def {{nama_fungsi}}(html_text, absolute_only=True):
    """Ekstrak semua URL dari <a href> di HTML."""
    parser = _LinkExtractor()
    parser.feed(html_text)
    if absolute_only:
        return [l for l in parser.links if l.startswith("http")]
    return parser.links
